+/** Record a target-specific relation event for pair tracking modifiers. */
+export function processPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    relation: Relation<Trait>,
+    target: Entity,
+    type: EventType
+) {
+    const instance = getTraitInstance(world[$internal].traitInstances, relation[$internal].trait);
+    if (!instance) return;
+
+    const relationId = relation[$internal].trait.id;
+    const key = `${relationId}:${target}`;
+    for (const query of instance.trackingQueries) {
+        if (!query.pairTrackingGroups.length) continue;
+        let affected = false;
+        for (const group of query.pairTrackingGroups) {
+            if (!group.pairs.some((pair) => {
+                const context = pair[$internal];
+                return context.relation === relation && (context.target === '*' || context.target === target);
+            })) continue;
+            affected = true;
+            let events = group.trackers.get(entity);
+            if (!events) group.trackers.set(entity, (events = new Map()));
+            const previous = events.get(key);
+            // Addition/removal of the same concrete pair within one observation
+            // window cancels, while replacement targets remain independent.
+            if ((previous === 'add' && type === 'remove') || (previous === 'remove' && type === 'add')) {
+                events.delete(key);
+            } else {
+                events.set(key, type);
+            }
+        }
+        if (!affected) continue;
+
+        const regularMatch = query.checkTracking(world, entity, type, instance.generationId, instance.bitflag);
+        const pairMatch = query.pairTrackingGroups.every((group) => {
+            const events = group.trackers.get(entity);
+            const matched = group.pairs.map((pair) => {
+                const context = pair[$internal];
+                const prefix = `${context.relation[$internal].trait.id}:`;
+                if (context.target === '*') {
+                    return [...(events?.entries() ?? [])].some(([eventKey, eventType]) =>
+                        eventKey.startsWith(prefix) && eventType === group.type
+                    );
+                }
+                return events?.get(`${prefix}${context.target}`) === group.type;
+            });
+            return group.logic === 'and' ? matched.every(Boolean) : matched.some(Boolean);
+        });
+        const relationMatch = !query.relationFilters?.length || query.relationFilters.every((pair) => hasRelationPair(world, entity, pair));
+        if (regularMatch && pairMatch && relationMatch) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
